PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE universes (
	id VARCHAR NOT NULL, 
	tenant_id VARCHAR NOT NULL, 
	name VARCHAR NOT NULL, 
	description TEXT, 
	created_by_user_id VARCHAR, 
	created_at DATETIME NOT NULL, updated_at TEXT, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_universe_tenant_name UNIQUE (tenant_id, name)
);
COMMIT;
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "universe_symbols"(symbol TEXT, tenant_id TEXT, universe_id TEXT);
COMMIT;
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE universe_equities(symbol TEXT);
COMMIT;
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE universe_analytics_cache (
	id VARCHAR NOT NULL, 
	tenant_id VARCHAR NOT NULL, 
	universe_id VARCHAR NOT NULL, 
	symbol VARCHAR NOT NULL, 
	analytics_snapshot_id VARCHAR, 
	analytics_asof DATETIME, 
	sector VARCHAR, 
	rating VARCHAR, 
	composite_score FLOAT, 
	confidence_score FLOAT, 
	quality FLOAT, 
	growth FLOAT, 
	value FLOAT, 
	momentum FLOAT, 
	risk FLOAT, 
	updated_at DATETIME NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_uac_tenant_universe_symbol UNIQUE (tenant_id, universe_id, symbol)
);
COMMIT;
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE users (
	id VARCHAR NOT NULL, 
	tenant_id VARCHAR, 
	email VARCHAR, 
	role VARCHAR, 
	created_at DATETIME, password_hash TEXT, is_active INTEGER DEFAULT 1, updated_at TEXT, 
	PRIMARY KEY (id)
);
COMMIT;
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE tenants (
	id VARCHAR NOT NULL, 
	name VARCHAR, 
	created_at DATETIME, is_active INTEGER DEFAULT 1, 
	PRIMARY KEY (id)
);
COMMIT;
